using SeedApi;

var client = new SeedApiClient();
await client._.BatchCreateAsync(
    new CreateVendorRequest
    {
        Vendors = new Dictionary<string, Vendor>()
        {
            {
                "key",
                new Vendor
                {
                    Id = "id",
                    Name = "name",
                    CreatedAt = "created_at",
                    UpdatedAt = "updated_at",
                }
            },
        },
    }
);
